// ── Check pipeline run result ─────────────────────────────
const result = $input.first().json;

if (result.status !== 'ok') {
  throw new Error(`Pipeline run failed: ${result.message || JSON.stringify(result)}`);
}

return [{
  json: {
    run_ok:   true,
    inserted: result.inserted,
    skipped:  result.skipped,
    errors:   result.errors,
    run_at:   result.run_at,
  }
}];

// ── Split event list into individual items ─────────────────
const data = $input.first().json;
const events = data.events || [];

if (events.length === 0) {
  return [];
}

// Return each event as a separate item for downstream processing
return events.map(event => ({ json: event }));

// ── Format Telegram alert per event type ──────────────────
//
// Alert templates:
//   IPO          → 📈 Upcoming IPO
//   DIVIDEND     → 💰 Dividend
//   RIGHTS_ISSUE → 📋 Rights Issue
//   STOCK_SPLIT  → ✂️ Stock Split
//   BONUS_SHARES → 🎁 Bonus Shares
//   BUYBACK      → 🔄 Buyback
//   SUSPENSION   → ⚠️ Trading Suspension
//   AGM          → 🏛 AGM (RUPS Tahunan)
//   EGM          → 🏛 EGM (RUPS Luar Biasa)
//   DELISTING    → 🚫 Delisting

const CHAT_ID = process.env.TELEGRAM_CHAT_ID || '-100123456789';

function fmtDate(d) {
  if (!d) return 'TBA';
  const dt = new Date(d);
  if (isNaN(dt)) return d;
  return dt.toLocaleDateString('id-ID', {
    day: '2-digit', month: 'short', year: 'numeric'
  });
}

function buildMessage(ev) {
  const ticker  = ev.ticker  || '-';
  const company = ev.company || ev.ticker || 'N/A';

  switch (ev.event_type) {
    case 'IPO':
      return [
        `📈 *Upcoming IPO*`,
        `Company      : ${company}`,
        `Ticker       : ${ticker}`,
        `Book-Build   : ${fmtDate(ev.book_build_start)} – ${fmtDate(ev.book_build_end)}`,
        `Listing Date : ${fmtDate(ev.listing_date)}`,
        ev.url ? `\n[IDX/e-IPO](${ev.url})` : '',
      ].filter(Boolean).join('\n');

    case 'DIVIDEND':
      return [
        `💰 *Dividend Announcement*`,
        `Ticker      : ${ticker}`,
        `Company     : ${company}`,
        `Ex-Date     : ${fmtDate(ev.ex_date)}`,
        `Record Date : ${fmtDate(ev.record_date)}`,
        ev.description ? `Detail      : ${ev.description}` : '',
        ev.url ? `\n[Detail](${ev.url})` : '',
      ].filter(Boolean).join('\n');

    case 'RIGHTS_ISSUE':
      return [
        `📋 *Rights Issue (HMETD)*`,
        `Ticker      : ${ticker}`,
        `Company     : ${company}`,
        `Ex-Date     : ${fmtDate(ev.ex_date)}`,
        `Record Date : ${fmtDate(ev.record_date)}`,
        ev.description ? `Detail      : ${ev.description}` : '',
        ev.url ? `\n[Detail](${ev.url})` : '',
      ].filter(Boolean).join('\n');

    case 'STOCK_SPLIT':
      return [
        `✂️ *Stock Split*`,
        `Ticker      : ${ticker}`,
        `Company     : ${company}`,
        `Efektif     : ${fmtDate(ev.event_date)}`,
        ev.description ? `Detail      : ${ev.description}` : '',
      ].filter(Boolean).join('\n');

    case 'BONUS_SHARES':
      return [
        `🎁 *Bonus Shares*`,
        `Ticker      : ${ticker}`,
        `Company     : ${company}`,
        `Tanggal     : ${fmtDate(ev.event_date)}`,
        ev.description ? `Detail      : ${ev.description}` : '',
      ].filter(Boolean).join('\n');

    case 'BUYBACK':
      return [
        `🔄 *Share Buyback*`,
        `Ticker      : ${ticker}`,
        `Company     : ${company}`,
        `Tanggal     : ${fmtDate(ev.event_date)}`,
      ].filter(Boolean).join('\n');

    case 'SUSPENSION':
      return [
        `⚠️ *Trading Suspension*`,
        `Ticker      : ${ticker}`,
        `Company     : ${company}`,
        `Tanggal     : ${fmtDate(ev.event_date)}`,
        `Alasan      : ${ev.description || 'Lihat pengumuman IDX'}`,
        ev.url ? `\n[Pengumuman](${ev.url})` : '',
      ].filter(Boolean).join('\n');

    case 'AGM':
      return [
        `🏛 *RUPS Tahunan (AGM)*`,
        `Ticker      : ${ticker}`,
        `Company     : ${company}`,
        `Tanggal     : ${fmtDate(ev.event_date)}`,
        ev.url ? `\n[Pengumuman](${ev.url})` : '',
      ].filter(Boolean).join('\n');

    case 'EGM':
      return [
        `🏛 *RUPS Luar Biasa (EGM)*`,
        `Ticker      : ${ticker}`,
        `Company     : ${company}`,
        `Tanggal     : ${fmtDate(ev.event_date)}`,
        ev.url ? `\n[Pengumuman](${ev.url})` : '',
      ].filter(Boolean).join('\n');

    case 'DELISTING':
      return [
        `🚫 *Delisting Notice*`,
        `Ticker      : ${ticker}`,
        `Company     : ${company}`,
        `Tanggal     : ${fmtDate(ev.event_date)}`,
        ev.url ? `\n[Detail](${ev.url})` : '',
      ].filter(Boolean).join('\n');

    default:
      return [
        `📌 *Market Event*`,
        `Type        : ${ev.event_type}`,
        `Ticker      : ${ticker}`,
        `Company     : ${company}`,
        `Tanggal     : ${fmtDate(ev.event_date)}`,
      ].join('\n');
  }
}

const event = $input.first().json;
const text  = buildMessage(event);

return [{
  json: {
    chat_id:                  CHAT_ID,
    text:                     text,
    parse_mode:               'Markdown',
    disable_web_page_preview: true,
    event_type:               event.event_type,
    ticker:                   event.ticker,
  }
}];
